jinjaPromptTemplate.template:
{{- bos_token -}}
{%- if (enable_thinking is defined and enable_thinking) or tools or messages[0]['role'] in ['system', 'developer'] -%}
    {{- '<|turn>system\n' -}}
    {{- '<|think|>\n' -}}
    {%- if messages[0]['role'] in ['system', 'developer'] -%}
        {%- set loop_messages = messages[1:] -%}
    {%- else -%}
        {%- set loop_messages = messages -%}
    {%- endif -%}
    {%- if tools -%}
        {%- for tool in tools -%}
            {{- '<|tool>' -}}
            {{- 'declaration:' + tool['function']['name'] -}}
            {{- '{description:<|"|>' + tool['function']['description'] + '<|"|>' -}}
            {%- if tool['function']['parameters'] -%}
                {{- ',parameters:{type:<|"|>OBJECT<|"|>}' -}}
            {%- endif -%}
            {{- '}' -}}
            {{- '<tool|>' -}}
        {%- endfor -%}
    {%- endif -%}
    {{- '<turn|>\n' -}}
{%- else -%}
    {%- set loop_messages = messages -%}
{%- endif -%}

{%- for message in loop_messages -%}
    {%- if message['role'] == 'tool' -%}
        {%- set prev_was_assistant = False -%}
        {%- if loop.index0 > 0 -%}
            {%- set prev = loop_messages[loop.index0 - 1] -%}
            {%- set prev_was_assistant = prev['role'] == 'assistant' -%}
        {%- endif -%}
        {%- if prev_was_assistant -%}
            {%- set tc_id = '' -%}
            {%- if message.get('tool_call_id') -%}
                {%- for tc in loop_messages[loop.index0 - 1].get('tool_calls', []) -%}
                    {%- if tc.get('id') == message['tool_call_id'] -%}
                        {%- set tc_id = tc['function']['name'] -%}
                    {%- endif -%}
                {%- endfor -%}
            {%- else -%}
                {%- set tc_id = message.get('name', 'unknown') -%}
            {%- endif -%}
            {{- '<|tool_response>' -}}
            {{- 'response:' + tc_id + '{value:<|"|>' + message['content'] + '<|"|>}' -}}
            {{- '<tool_response|>' -}}
        {%- endif -%}
    {%- elif message['role'] == 'user' -%}
        {%- set prev_was_model = False -%}
        {%- if loop.index0 > 0 -%}
            {%- set prev = loop_messages[loop.index0 - 1] -%}
            {%- set prev_was_model = prev['role'] == 'model' or prev['role'] == 'assistant' -%}
        {%- endif -%}
        {%- if not prev_was_model -%}
            {{- '<|turn>user\n' -}}
        {%- endif -%}
        {%- if message['content'] is string -%}
            {{- message['content'] | trim -}}
        {%- else -%}
            {%- for item in message['content'] -%}
                {%- if item['type'] == 'text' -%}
                    {{- item['text'] | trim -}}
                {%- endif -%}
            {%- endfor -%}
        {%- endif -%}
        {{- '<turn|>\n' -}}
    {%- elif message['role'] == 'assistant' or message['role'] == 'model' -%}
        {%- if loop.first or loop_messages[loop.index0 - 1]['role'] != 'assistant' -%}
            {{- '<|turn>model\n' -}}
        {%- endif -%}
        {%- if message['tool_calls'] -%}
            {%- for tc in message['tool_calls'] -%}
                {{- '<|tool_call>call:' + tc['function']['name'] + '{' + tc['function']['arguments'] + '}<tool_call|>' -}}
            {%- endfor -%}
        {%- endif -%}
        {%- if message['content'] is string and message['content'] | trim | length > 0 -%}
            {{- message['content'] | trim -}}
        {%- endif -%}
        {%- if not message.get('tool_calls') -%}
            {{- '<turn|>\n' -}}
        {%- endif -%}
    {%- endif -%}
{%- endfor -%}

{%- if add_generation_prompt -%}
    {{- '<|turn>model\n' -}}
    {%- if not (enable_thinking is defined and enable_thinking) -%}
        {{- '<|channel>thought\n<channel|>' -}}
    {%- endif -%}
{%- endif -%}
